	@Test
	public void nestedGroupFilterDoesNotSeeOuterBind() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "SELECT ?s ?v ?z WHERE {\n"
				+ "  BIND(4 AS ?z)\n"
				+ "  { ?s :p ?v . FILTER(?v = ?z) }\n"
				+ "}";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).isEmpty();
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("a native root must not flatten a nested variable-scope boundary")
				.isEqualTo(compiledBefore);
	}

	@Test
	public void postQueryValuesWithTwoStringBindingsJoinsStoredTerms() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "SELECT ?s ?o1 ?o2 WHERE {\n"
				+ "  ?s ?p1 ?o1 .\n"
				+ "  ?s ?p2 ?o2 .\n"
				+ "} VALUES (?o1 ?o2) {\n"
				+ "  (\"Alan\" \"alan@example.org\")\n"
				+ "}";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).singleElement().satisfies(bindings -> {
				assertThat(bindings.getValue("s")).isEqualTo(conn.getValueFactory().createIRI(EX, "a"));
				assertThat(bindings.getValue("o1")).isEqualTo(conn.getValueFactory().createLiteral("Alan"));
				assertThat(bindings.getValue("o2"))
						.isEqualTo(conn.getValueFactory().createLiteral("alan@example.org"));
			});
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("string-valued post-query VALUES should stay on the native row path")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void postQueryValuesStillUsesRdfTermIdentityForNumericLiterals() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n"
				+ "SELECT ?s WHERE { ?s :numericValue ?value }\n"
				+ "VALUES ?value { \"1\"^^xsd:integer }";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).isEmpty();
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("numeric term identity is unsafe for the native raw-id VALUES path")
				.isEqualTo(compiledBefore);
	}

	@Test
	public void computedStrlenOverSyntheticValues() {
		String query = "SELECT ?x ?length WHERE {\n"
				+ "  VALUES ?x { \"abcdefghij\" \"abcdefghijkl\" }\n"
				+ "  BIND(STRLEN(?x) AS ?length)\n"
				+ "}";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		List<String> nativeRows = rows(query, true, null, null);
		assertThat(nativeRows).isEqualTo(rows(query, false, null, null));
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("a computed extension must not consume a plan-local synthetic id")
				.isEqualTo(compiledBefore);
		assertThat(nativeRows).hasSize(2);
		assertThat(nativeRows.get(0)).contains("length=\"10\"");
		assertThat(nativeRows.get(1)).contains("length=\"12\"");
	}

	@Test
	public void filterStrlenOverSyntheticValuesUsesMaterializedValue() {
		String query = "SELECT ?x WHERE {\n"
				+ "  VALUES ?x { \"abcdefghij\" }\n"
				+ "  FILTER(STRLEN(?x) = 10)\n"
				+ "}";

		List<String> nativeRows = rows(query, true, null, null);
		assertThat(nativeRows).isEqualTo(rows(query, false, null, null));
		assertThat(nativeRows).containsExactly("[x=\"abcdefghij\"]");
	}

	@Test
	public void copiedExternalBindingAbsentFromStoreMatchesGeneric() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "SELECT ?s ?external ?copy WHERE {\n"
				+ "  ?s :p ?o .\n"
				+ "  BIND(?external AS ?copy)\n"
				+ "}";
		Value external = repository.getValueFactory().createIRI(EX, "not-present-in-store");

		List<String> nativeRows = rows(query, true, "external", external);
		assertThat(nativeRows).isEqualTo(rows(query, false, "external", external));
		assertThat(nativeRows).containsExactly(
				"[copy=http://example.org/not-present-in-store;s=http://example.org/s4]");
	}

	@Test
	public void languageTagCaseVariantsDeduplicate() {
		String query = "SELECT DISTINCT ?value WHERE {\n"
				+ "  VALUES ?value { \"hello\"@EN \"hello\"@en }\n"
				+ "}";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		List<String> nativeRows = rows(query, true, null, null);
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("language VALUES should remain native with a value-safe representation")
				.isGreaterThan(compiledBefore);
		assertThat(nativeRows).isEqualTo(rows(query, false, null, null));
		assertThat(nativeRows).hasSize(1);
	}

	@Test
	public void languageTagCaseVariantsUseRdfTermEqualityForSameTerm() {
		String query = "SELECT ?value1 ?value2 WHERE {\n"
				+ "  VALUES (?value1 ?value2) { (\"hello\"@EN \"hello\"@en) }\n"
				+ "  FILTER(sameTerm(?value1, ?value2))\n"
				+ "}";

		List<String> nativeRows = rows(query, true, null, null);
		assertThat(nativeRows).isEqualTo(rows(query, false, null, null));
		assertThat(nativeRows).hasSize(1);
	}

	@Test
	public void scopedGroupInsideExistsMatchesGeneric() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "SELECT ?s WHERE {\n"
				+ "  BIND(4 AS ?z)\n"
				+ "  FILTER EXISTS {\n"
				+ "    { ?s :p ?v . FILTER(?v = ?z) }\n"
				+ "  }\n"
				+ "}";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		List<String> nativeRows = rows(query, true, null, null);
		assertThat(nativeRows).isEqualTo(rows(query, false, null, null));
		assertThat(nativeRows).containsExactly("[]");
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("native EXISTS must decline an unmodeled nested variable-scope boundary")
				.isEqualTo(compiledBefore);
	}

	@Test
	public void valuedOutsideOptionalVarIsStillDetected() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "SELECT ?s ?value WHERE {\n"
				+ "  OPTIONAL { ?s :optional ?value }\n"
				+ "  ?other :required ?value\n"
				+ "}\n"
				+ "VALUES ?value { \"target\" }";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		List<String> nativeRows = rows(query, true, null, null);
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("optimizer-valued statement variables retain identity outside OPTIONAL")
				.isEqualTo(compiledBefore);
		assertThat(nativeRows).isEqualTo(rows(query, false, null, null));
		assertThat(nativeRows).containsExactly("[s=http://example.org/optionalSubject;value=\"target\"]");
	}

	private List<String> rows(String query, boolean nativeEnabled, String bindingName, Value bindingValue) {
		String previous = System.getProperty(NATIVE_FLAG);
		try {
			System.setProperty(NATIVE_FLAG, Boolean.toString(nativeEnabled));
			try (SailRepositoryConnection conn = repository.getConnection()) {
				TupleQuery tupleQuery = conn.prepareTupleQuery(query);
				if (bindingName != null) {
					tupleQuery.setBinding(bindingName, bindingValue);
				}
				return QueryResults.asList(tupleQuery.evaluate())
						.stream()
						.map(LmdbNativeScopeAndValuesRegressionTest::canonical)
						.sorted()
						.collect(Collectors.toList());
			}
		} finally {
			restoreNativeFlag(previous);
		}
	}

	private static String canonical(BindingSet bindings) {
		return bindings.getBindingNames()
				.stream()
				.sorted()
				.filter(name -> bindings.getValue(name) != null)
				.map(name -> name + "=" + bindings.getValue(name))
				.collect(Collectors.joining(";", "[", "]"));
	}

	private static void restoreNativeFlag(String previous) {
		if (previous == null) {
			System.clearProperty(NATIVE_FLAG);
		} else {
			System.setProperty(NATIVE_FLAG, previous);
		}
	}
